/*
输入W和n
输入
初始化
状压DP
输出结果 
*/
#include <bits/stdc++.h>
#define int long long
using namespace std;
const int N = 20;
int a, b, t[N], w[N], T[1 << N], W[1 << N], dp[1 << N];
signed main() {
	cin >> a >> b;
	const int mx = (1 << b) - 1;
	for (int i = 1; i <= b; i++) {
		cin >> t[i] >> w[i];
	}
	for (int i = 0; i <= mx; i++) {
		for (int j = 1; j <= b; j++) {
			if (i & (1 << (j - 1))) {
				T[i] = max (T[i], t[j]);
				W[i] += w[j];
			}
		}
	}
	memset (dp, 0x3f, sizeof (dp));
	dp[0] = 0;
	for (int i = 0; i <= mx; i++) {
		for (int j = i;; j = i & (j - 1)) {
			if (W[i ^ j] <= a) {
				dp[i] = min (dp[i], dp[j] + T[i ^ j]);
			}
			if (!j) {
				break;
			}
		}
	}
	cout << dp[mx];
	return 0;
}
